INSERT INTO `learning_content` (`id`, `page_slug`, `section_id`, `title`, `content`, `modified_at`) VALUES
(1, 'ecg', 'intro', 'What is ECG?', 'Electrocardiography (ECG or EKG) measures the electrical activity of the heart over time using electrodes placed on the skin. It captures the depolarization and repolarization of heart muscles during each cardiac cycle.', '2026-03-09 04:55:23'),
(2, 'eeg', 'intro', 'What is EEG?', 'Electroencephalography (EEG) records electrical activity of the brain through electrodes placed on the scalp. It monitors synchronized neuronal firing patterns, providing a window into brain function and neurological disorders.', '2026-03-09 04:55:23'),
(3, 'emg', 'intro', 'What is EMG?', 'Electromyography (EMG) measures the electrical activity produced by skeletal muscles. When muscles are active, they produce electrical signals that are proportional to the level of muscle contraction. EMG is essential for diagnosing neuromuscular disorders and assessing muscle function.', '2026-03-09 04:55:23'),
(7, 'electrode_placement', 'intro', 'Electrode Placement Guide', 'Accurate electrode placement is the most critical factor in high-quality biopotential recording. Standardized systems, such as the 10-20 system for EEG or Einthoven\'s triangle for ECG, ensure that results are reproducible across different subjects and clinical environments. This guide provides step-by-step protocols for positioning electrodes to minimize artifacts and maximize Signal-to-Noise Ratio (SNR), forming the essential first step for any advanced AI-driven signal analysis.', '2026-03-09 05:15:39');

